module top_module(
    input clk,
    input rst,
    input [2:0] reg_src,
    input [2:0] reg_dst,
    input [2:0] reg_wrt_dst,
    input reg_wrt,
    input [7:0] wrt_data,
    output reg [7:0] reg_src_dat,
    output reg [7:0] reg_dst_dat
);reg [7:0] mem_reg [7:0];

    always @(posedge clk) begin
        if (reg_wrt == 1)
            mem_reg[reg_wrt_dst] = wrt_data;
        reg_src_dat = mem_reg[reg_src];
        reg_dst_dat = mem_reg[reg_dst];
    end

    always @(rst) begin
        if (rst == 1) begin
            mem_reg[0]  = 8'b00000000;
            mem_reg[1]  = 8'b00000001;
            mem_reg[2]  = 8'b00000010;
            mem_reg[3]  = 8'b00000011;
            mem_reg[4]  = 8'b00000100;
            mem_reg[5]  = 8'b00000101;
            mem_reg[6]  = 8'b00000110;
            mem_reg[7]  = 8'b00000111;
        end
    end

endmodule
